# Pinning Resource Graph results to an Azure Dashboard

# Option 1: Pin from the Explorer UI
# After running a query in the portal, click 'Pin to dashboard'
# The tile updates automatically each time the dashboard loads.

# Option 2: Create a dashboard tile via ARM template
# This allows you to deploy standardised governance dashboards via IaC.

cat > governance-dashboard.json << 'ENDJSON'
{
  "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
  "contentVersion": "1.0.0.0",
  "resources": [
    {
      "type": "Microsoft.Portal/dashboards",
      "apiVersion": "2020-09-01-preview",
      "name": "governance-overview",
      "location": "[resourceGroup().location]",
      "properties": {
        "lenses": [
          {
            "order": 0,
            "parts": [
              {
                "position": {"x":0,"y":0,"colSpan":6,"rowSpan":4},
                "metadata": {
                  "type": "Extension/HubsExtension/PartType/ArgQueryGridTile",
                  "settings": {
                    "content": {
                      "query": "Resources | where type !startswith 'microsoft.resources' | summarize Count = count() by type | order by Count desc | top 10 by Count",
                      "title": "Top 10 Resource Types",
                      "queryScope": {"subscriptionIds": ["<sub-id>"]}
                    }
                  }
                }
              },
              {
                "position": {"x":6,"y":0,"colSpan":6,"rowSpan":4},
                "metadata": {
                  "type": "Extension/HubsExtension/PartType/ArgQueryGridTile",
                  "settings": {
                    "content": {
                      "query": "Resources | where type !startswith 'microsoft.resources' | where array_length(bag_keys(tags)) == 0 | summarize Count = count() by subscriptionId",
                      "title": "Untagged Resources by Subscription",
                      "queryScope": {"subscriptionIds": ["<sub-id>"]}
                    }
                  }
                }
              }
            ]
          }
        ],
        "metadata": {"model": {"timeRange": {"type": "MsPortalFx.Composition.Configuration.ValueTypes.TimeRange"}}}
      }
    }
  ]
}
ENDJSON

az deployment group create \
  --resource-group rg-dashboards \
  --template-file governance-dashboard.json
